const messages=document.getElementById("messages"),replyForm=document.getElementById("replyForm"),responseInput=document.getElementById("response"),chatHistory=[];function createMessage(e,t){const s=document.createElement("div");s.className=`message ${e}`,s.setAttribute("data-role","ai"===e?"AI":"Human");const r=document.createElement("p");return r.textContent=t,s.appendChild(r),s}function renderMessages(){messages.innerHTML="",chatHistory.forEach(({role:e,text:t})=>{messages.appendChild(createMessage(e,t))}),messages.scrollTop=messages.scrollHeight}async function fetchPrompt(){try{const e=await fetch("getprompt");if(!e.ok)throw new Error(`HTTP ${e.status}`);const t=await e.text(),s=JSON.parse(t);chatHistory.push({role:"server",text:s.value||"Received empty prompt response."})}catch(e){chatHistory.push({role:"server",text:`Unable to fetch prompt: ${e.message}`})}finally{renderMessages()}}replyForm.addEventListener("keydown",e=>{"Enter"!==e.key||e.shiftKey||(e.preventDefault(),replyForm.dispatchEvent(new Event("submit")))}),replyForm.addEventListener("submit",e=>{e.preventDefault();const t=responseInput.value.trim();t&&(chatHistory.push({role:"ai",text:t}),responseInput.value="",renderMessages())}),document.addEventListener("DOMContentLoaded",()=>{fetchPrompt(),renderMessages()});